module top_module(
  input [3:0] obf_A,
  input [3:0] B,
  input [1:0] op,
  output reg eq
);always @ (obf_A, B, op) begin
    case(op)
      2'b00: eq = (obf_A == B);
      2'b01: eq = (obf_A > B);
      2'b10: eq = (obf_A < B);
      2'b11: eq = (obf_A != B);
      default: eq = 0;
    endcase
  end

endmodule
